import React, { useState, useEffect } from 'react';
import './ConnectUPI.css';

function ConnectUPI({ onBack, onConnected }) {
  const [step, setStep] = useState('select'); // select, connecting, connected
  const [selectedProvider, setSelectedProvider] = useState(null);
  const [connecting, setConnecting] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState(null);
  const [error, setError] = useState(null);

  const upiProviders = [
    {
      id: 'google-pay',
      name: 'Google Pay',
      icon: '💳',
      color: '#4285f4',
      description: 'Connect your Google Pay account'
    },
    {
      id: 'phonepe',
      name: 'PhonePe',
      icon: '📱',
      color: '#5f259f',
      description: 'Connect your PhonePe account'
    },
    {
      id: 'paytm',
      name: 'Paytm',
      icon: '💰',
      color: '#00b9f5',
      description: 'Connect your Paytm wallet'
    },
    {
      id: 'amazon-pay',
      name: 'Amazon Pay',
      icon: '🛒',
      color: '#ff9900',
      description: 'Connect your Amazon Pay account'
    },
    {
      id: 'bhim',
      name: 'BHIM UPI',
      icon: '🏦',
      color: '#0066cc',
      description: 'Connect via BHIM UPI'
    },
    {
      id: 'account-aggregator',
      name: 'Account Aggregator',
      icon: '🔗',
      color: '#667eea',
      description: 'Connect all banks via RBI-approved AA',
      recommended: true
    }
  ];

  useEffect(() => {
    // Check if returning from OAuth callback
    const urlParams = new URLSearchParams(window.location.search);
    const upiConnected = urlParams.get('upi_connected');
    const provider = urlParams.get('provider');
    
    if (upiConnected === 'true' && provider) {
      setStep('connected');
      setSelectedProvider(upiProviders.find(p => p.id === provider));
      checkConnectionStatus();
    }
  }, []);

  const checkConnectionStatus = async () => {
    try {
      const response = await fetch('/api/upi/status');
      const data = await response.json();
      setConnectionStatus(data);
    } catch (err) {
      console.error('Failed to check connection status:', err);
    }
  };

  const handleConnect = async (provider) => {
    setSelectedProvider(provider);
    setConnecting(true);
    setError(null);
    setStep('connecting');

    try {
      // Initiate OAuth flow
      const response = await fetch(`/api/upi/auth/${provider.id}`, {
        method: 'GET',
        credentials: 'include'
      });

      if (response.redirected) {
        // Redirect to OAuth provider
        window.location.href = response.url;
      } else {
        const data = await response.json();
        if (data.auth_url) {
          window.location.href = data.auth_url;
        } else {
          throw new Error('No authorization URL received');
        }
      }
    } catch (err) {
      setError(`Failed to connect: ${err.message}`);
      setConnecting(false);
      setStep('select');
    }
  };

  const handleDisconnect = async () => {
    if (!window.confirm('Are you sure you want to disconnect your UPI account?')) {
      return;
    }

    try {
      await fetch('/api/upi/disconnect', {
        method: 'POST',
        credentials: 'include'
      });
      
      setStep('select');
      setSelectedProvider(null);
      setConnectionStatus(null);
    } catch (err) {
      setError('Failed to disconnect');
    }
  };

  const handleManualSync = async () => {
    try {
      setConnecting(true);
      await fetch('/api/upi/sync', {
        method: 'POST',
        credentials: 'include'
      });
      
      alert('Sync completed successfully!');
      checkConnectionStatus();
    } catch (err) {
      alert('Sync failed: ' + err.message);
    } finally {
      setConnecting(false);
    }
  };

  const renderProviderSelection = () => (
    <div className="connect-upi-page">
      <div className="connect-header">
        <button className="back-button" onClick={onBack}>
          ← Back
        </button>
        <h1>🔗 Connect Your UPI App</h1>
        <p className="subtitle">Choose your UPI provider to get started</p>
      </div>

      {error && (
        <div className="error-banner">
          ⚠️ {error}
        </div>
      )}

      <div className="providers-grid">
        {upiProviders.map(provider => (
          <div
            key={provider.id}
            className={`provider-card ${provider.recommended ? 'recommended' : ''}`}
            style={{ borderColor: provider.color }}
          >
            {provider.recommended && (
              <div className="recommended-badge">⭐ Recommended</div>
            )}
            
            <div className="provider-icon" style={{ color: provider.color }}>
              {provider.icon}
            </div>
            
            <h3>{provider.name}</h3>
            <p className="provider-description">{provider.description}</p>
            
            <button
              className="connect-button"
              style={{ background: provider.color }}
              onClick={() => handleConnect(provider)}
              disabled={connecting}
            >
              {connecting && selectedProvider?.id === provider.id
                ? '⏳ Connecting...'
                : '🔗 Connect'}
            </button>
          </div>
        ))}
      </div>

      <div className="info-section">
        <h2>🔒 How It Works</h2>
        <div className="steps-grid">
          <div className="step-card">
            <div className="step-number">1</div>
            <h3>Select Provider</h3>
            <p>Choose your UPI app from the options above</p>
          </div>
          <div className="step-card">
            <div className="step-number">2</div>
            <h3>Authenticate</h3>
            <p>Login to your UPI app securely</p>
          </div>
          <div className="step-card">
            <div className="step-number">3</div>
            <h3>Grant Permission</h3>
            <p>Allow read-only access to transactions</p>
          </div>
          <div className="step-card">
            <div className="step-number">4</div>
            <h3>Auto-Sync</h3>
            <p>We'll fetch and analyze automatically</p>
          </div>
        </div>

        <div className="security-info">
          <h3>🛡️ Your Security is Our Priority</h3>
          <div className="security-features">
            <div className="security-item">
              <span className="security-icon">🔐</span>
              <div>
                <strong>Bank-Level Encryption</strong>
                <p>All data encrypted with industry standards</p>
              </div>
            </div>
            <div className="security-item">
              <span className="security-icon">👁️</span>
              <div>
                <strong>Read-Only Access</strong>
                <p>We can only view, never make payments</p>
              </div>
            </div>
            <div className="security-item">
              <span className="security-icon">🔄</span>
              <div>
                <strong>Revoke Anytime</strong>
                <p>Disconnect with one click, no questions asked</p>
              </div>
            </div>
            <div className="security-item">
              <span className="security-icon">✅</span>
              <div>
                <strong>RBI Compliant</strong>
                <p>Follows Reserve Bank of India guidelines</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  const renderConnecting = () => (
    <div className="connect-upi-page">
      <div className="connecting-container">
        <div className="connecting-animation">
          <div className="spinner-large"></div>
        </div>
        <h2>Connecting to {selectedProvider?.name}...</h2>
        <p>You'll be redirected to authenticate</p>
        <div className="connecting-steps">
          <div className="connecting-step active">
            <span className="step-icon">✓</span>
            <span>Provider selected</span>
          </div>
          <div className="connecting-step active">
            <span className="step-icon">⏳</span>
            <span>Redirecting to {selectedProvider?.name}</span>
          </div>
          <div className="connecting-step">
            <span className="step-icon">○</span>
            <span>Authenticate and grant permissions</span>
          </div>
          <div className="connecting-step">
            <span className="step-icon">○</span>
            <span>Fetching transaction history</span>
          </div>
        </div>
      </div>
    </div>
  );

  const renderConnected = () => (
    <div className="connect-upi-page">
      <div className="connected-container">
        <div className="success-icon">✅</div>
        <h1>Successfully Connected!</h1>
        <p className="success-message">
          Your {selectedProvider?.name} account is now linked
        </p>

        {connectionStatus && (
          <div className="connection-details">
            <div className="detail-card">
              <span className="detail-label">Provider</span>
              <span className="detail-value">{connectionStatus.provider}</span>
            </div>
            <div className="detail-card">
              <span className="detail-label">Status</span>
              <span className="detail-value status-active">🟢 Active</span>
            </div>
            <div className="detail-card">
              <span className="detail-label">Last Synced</span>
              <span className="detail-value">
                {connectionStatus.last_synced 
                  ? new Date(connectionStatus.last_synced).toLocaleString()
                  : 'Never'}
              </span>
            </div>
            <div className="detail-card">
              <span className="detail-label">Transactions</span>
              <span className="detail-value">
                {connectionStatus.transaction_count || 0}
              </span>
            </div>
          </div>
        )}

        <div className="connected-actions">
          <button className="primary-button" onClick={() => onConnected && onConnected()}>
            📊 View Dashboard
          </button>
          <button className="secondary-button" onClick={handleManualSync} disabled={connecting}>
            {connecting ? '⏳ Syncing...' : '🔄 Sync Now'}
          </button>
          <button className="danger-button" onClick={handleDisconnect}>
            🔌 Disconnect
          </button>
        </div>

        <div className="auto-sync-info">
          <h3>⚡ Automatic Sync Enabled</h3>
          <p>
            Your transactions will be automatically synced every 6 hours.
            You'll always have up-to-date financial insights without any manual work!
          </p>
        </div>
      </div>
    </div>
  );

  return (
    <div className="connect-upi-wrapper">
      {step === 'select' && renderProviderSelection()}
      {step === 'connecting' && renderConnecting()}
      {step === 'connected' && renderConnected()}
    </div>
  );
}

export default ConnectUPI;
